Describe 'New-MarkdownSummary' {

    BeforeAll {
        [PSCustomObject[]]$runs = @(
            (ConvertFrom-JUnitXml        -FilePath $script:JUnitRun1 -RunId 'run1')
            (ConvertFrom-JUnitXml        -FilePath $script:JUnitRun2 -RunId 'run2')
